/**
 * Debounce utility to prevent rapid-fire function calls
 * Used in pages to prevent multiple data reloads
 */

/**
 * Creates a debounced version of a function
 * @param func The function to debounce
 * @param wait Wait time in milliseconds
 */
export function debounce<T extends (...args: any[]) => any>(
  func: T,
  wait: number
): (...args: Parameters<T>) => void {
  let timeoutId: ReturnType<typeof setTimeout> | null = null

  return function (...args: Parameters<T>) {
    if (timeoutId) {
      clearTimeout(timeoutId)
    }

    timeoutId = setTimeout(() => {
      func(...args)
      timeoutId = null
    }, wait)
  }
}

/**
 * Creates a throttled version of a function
 * @param func The function to throttle
 * @param limit Time limit in milliseconds
 */
export function throttle<T extends (...args: any[]) => any>(
  func: T,
  limit: number
): (...args: Parameters<T>) => void {
  let lastCall = 0
  let timeoutId: ReturnType<typeof setTimeout> | null = null

  return function (...args: Parameters<T>) {
    const now = Date.now()

    if (now - lastCall >= limit) {
      lastCall = now
      func(...args)
    } else if (!timeoutId) {
      // Schedule a call at the end of the limit period
      timeoutId = setTimeout(() => {
        lastCall = Date.now()
        func(...args)
        timeoutId = null
      }, limit - (now - lastCall))
    }
  }
}

/**
 * Hook-friendly debounce that works with React refs
 * Prevents stale closure issues
 */
export function createDebouncedLoader(
  loadFn: () => Promise<void>,
  wait: number = 1000
): () => void {
  let lastCallTime = 0

  return () => {
    const now = Date.now()
    if (now - lastCallTime >= wait) {
      lastCallTime = now
      loadFn()
    }
  }
}
